class Solution {
public:
    string largestPalindrome(int n, int k) {
        string res = "";
        for (int i = pow(10, n - 1); i < pow(10, n); i++) {
            string str = to_string(i);
            if (isPalindrome(str) && i % k == 0) {
                res = max(res, str);
            }
        }
        return res;
    }

    bool isPalindrome(string s) {
        int left = 0, right = s.size() - 1;
        while (left < right) {
            if (s[left] != s[right]) return false;
            left++;
            right--;
        }
        return true;
    }
};
```

